const item = $input.first().json;
const video_id = item.video_id || (item.body && item.body.video_id) || null;
if (!video_id) throw new Error('video_id obrigatório.');
return [{ json: { video_id } }];

const cenas = $('Ler Cenas Pendentes').all().map(i => i.json);
const total = Array.isArray(cenas[0]) ? cenas[0].length : cenas.length;
return [{ json: { success: true, pendentes: total, mensagem: 'Regeneração iniciada.' } }];

// Separa cenas com nota de correção (Claude reescreve) vs sem nota (gera direto)
const cenasRaw = $('Ler Cenas Pendentes').all().map(i => i.json);
const cenas = Array.isArray(cenasRaw[0]) ? cenasRaw[0] : cenasRaw;

const comNota = cenas.filter(c => c.nota_correcao && c.nota_correcao.trim());
const semNota = cenas.filter(c => !c.nota_correcao || !c.nota_correcao.trim());

var staticData = $getWorkflowStaticData('global');
staticData.cenasComNota = comNota;
staticData.cenasSemNota = semNota;
staticData.videoId = $('Normalizar Input').first().json.video_id;

const videoArr = $('Ler Vídeo').all().map(i => i.json);
const video = Array.isArray(videoArr[0]) ? videoArr[0][0] : videoArr[0];
staticData.formato = video?.formato || 'shorts';

return [{ json: { comNota: comNota.length, semNota: semNota.length, total: cenas.length, _temNotas: comNota.length > 0 } }];

// Monta prompt para Claude reescrever os prompt_flux das cenas com nota
var staticData = $getWorkflowStaticData('global');
const cenas = staticData.cenasComNota || [];

const cenasTexto = cenas.map(c =>
  `CENA ${c.numero} (id: ${c.id}):\nPrompt atual: ${c.prompt_flux}\nNota de correção: ${c.nota_correcao}\nPersonagem presente: ${c.personagem_presente}\nRedux strength: ${c.redux_strength || 'null'}`
).join('\n\n---\n\n');

const systemPrompt = `Você é um diretor artístico de claymation horror. Receba prompts FLUX com notas de correção e reescreva APENAS os prompts corrigidos.

REGRAS:
1. Manter EXATAMENTE a mesma estrutura: claymation_stoners... ANGLE... SUBJECT... LIGHT... FOREGROUND... MIDGROUND... BACKGROUND... COLOR
2. NUNCA partes do corpo no FOREGROUND (mãos, dedos, ombros) — gera duplicação
3. NUNCA composição split/dividida — FLUX não entende
4. "single character only, one clay figure" obrigatório em cenas com personagem
5. Aplicar a correção descrita na nota mantendo o restante do prompt

Responda APENAS com JSON válido, sem markdown:
{"cenas": [{"id": "uuid", "prompt_flux": "prompt corrigido completo"}]}`;

const userMessage = `Reescreva os prompts FLUX aplicando as notas de correção:\n\n${cenasTexto}`;

return [{ json: { _systemPrompt: systemPrompt, _userMessage: userMessage } }];

// Parse resposta do Claude e atualiza prompts no Supabase
const response = $input.first().json;
const config = $('Configuração').first().json;

let cenasCorrigidas = [];
try {
  const text = response.text || response.response || '';
  const clean = text.replace(/```json|```/g, '').trim();
  cenasCorrigidas = JSON.parse(clean).cenas || [];
} catch(e) {
  return [{ json: { _erro: 'Parse falhou: ' + e.message } }];
}

const headers = {
  'apikey': config.SUPABASE_SERVICE_KEY,
  'Authorization': 'Bearer ' + config.SUPABASE_SERVICE_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

let atualizadas = 0;
for (const c of cenasCorrigidas) {
  if (!c.id || !c.prompt_flux) continue;
  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: config.SUPABASE_URL + '/rest/v1/cenas?id=eq.' + c.id,
      headers,
      body: { prompt_flux: c.prompt_flux, nota_correcao: null }
    });
    atualizadas++;
  } catch(e) {}
}

return [{ json: { _promptsAtualizados: atualizadas } }];

var response = $input.first().json;
