var response = $input.first().json;
var staticData = $getWorkflowStaticData('global');
var meta = $('Montar Payload').first().json;
staticData.imgPromptId = response.prompt_id;
staticData.imgHistoryUrl = staticData.comfyuiUrl + '/history/' + response.prompt_id;
staticData.imgRetries = 0;
return [{ json: { promptId: response.prompt_id, cenaId: meta.cenaId, cenaNumero: meta.cenaNumero, videoId: meta.videoId, personagem_presente: meta.personagem_presente, _isThumbnail: false } }];

var input = $('Buscar Resultado').first().json;
var staticData = $getWorkflowStaticData('global');
var promptId = staticData.imgPromptId;
staticData.imgRetries = (staticData.imgRetries || 0) + 1;
var pronto = false; var filename = null;
try {
  var hist = input[promptId];
  if (hist && hist.outputs) {
    var keys = Object.keys(hist.outputs);
    for (var k = 0; k < keys.length; k++) {
      var nodeOut = hist.outputs[keys[k]];
      if (nodeOut.images && nodeOut.images.length > 0) { filename = nodeOut.images[0].filename; pronto = true; break; }
    }
  }
} catch(e) {}
var meta = $('Preparar Polling Imagem').first().json;
return [{ json: { _ready: pronto, filename: filename, downloadUrl: pronto ? (staticData.comfyuiUrl + '/view?filename=' + encodeURIComponent(filename) + '&type=output') : null, cenaId: meta.cenaId, cenaNumero: meta.cenaNumero, videoId: meta.videoId, personagem_presente: meta.personagem_presente, _isThumbnail: false } }];

const meta = $input.first().json;
var staticData = $getWorkflowStaticData('global');
const config = $('Configuração').first().json;

const storagePath = meta._isThumbnail
  ? meta.videoId + '/thumbnail.png'
  : meta.videoId + '/cena_' + meta.cenaNumero + '.png';

const publicUrl = config.SUPABASE_URL + '/storage/v1/object/public/imagens/' + storagePath;

// ==========================================================
// REGRA 29 — continuidade visual entre cenas
// Copia a imagem recém-gerada do /output do ComfyUI pro /input
// com nome fixo 'continuity_{videoId}.png', pra próxima cena
// com continuidade=true usar como Redux reference.
// ==========================================================
if (meta.personagem_presente && !meta._isThumbnail) {
  try {
    const comfyuiUrl = staticData.comfyuiUrl;
    const continuityName = 'continuity_' + meta.videoId + '.png';

    // 1. Baixar a imagem do /output via /view
    const imageBuffer = await this.helpers.httpRequest({
      method: 'GET',
      url: comfyuiUrl + '/view',
      qs: {
        filename: meta.filename,
        type: 'output',
        subfolder: ''
      },
      encoding: 'arraybuffer',
      returnFullResponse: false
    });

    // 2. Reupload via /upload/image como multipart
    await this.helpers.httpRequest({
      method: 'POST',
      url: comfyuiUrl + '/upload/image',
      formData: {
        image: {
          value: Buffer.from(imageBuffer),
          options: {
            filename: continuityName,
            contentType: 'image/png'
          }
        },
        overwrite: 'true',
        type: 'input',
        subfolder: ''
      }
    });

    // 3. Guardar referência pra próxima cena usar no LoadImage
    staticData.lastPersonagemImage = continuityName;
  } catch (e) {
    console.log('Regra 29 falhou: ' + e.message);
  }
}

return [{ json: {
  downloadUrl: meta.downloadUrl,
  uploadUrl: config.SUPABASE_URL + '/storage/v1/object/imagens/' + storagePath,
  publicUrl: publicUrl,
  cenaId: meta.cenaId,
  cenaNumero: meta.cenaNumero,
  videoId: meta.videoId,
  _isThumbnail: meta._isThumbnail,
  supabaseKey: config.SUPABASE_SERVICE_KEY
} }];

// ===================================================================
// COPIAR OUTPUT → INPUT (ComfyUI) — Regra 29 Continuidade
// ===================================================================
// Quando uma cena com personagem é gerada, o ComfyUI salva no /output/.
// Para a próxima cena usar como referência Redux (continuidade=true),
// precisamos copiar do /output/ para o /input/, porque LoadImage só lê
// de /input/.
//
// Estratégia: baixa o PNG via /view (type=output) e sobe via
// /upload/image (multipart) com nome fixo continuity_{videoId}.png.
// O arquivo é sobrescrito a cada cena com personagem — auto-limpa.
//
// Só roda se personagem_presente && !_isThumbnail. Caso contrário,
// passa o item adiante sem alterações.
// ===================================================================

const meta = $input.first().json;
var staticData = $getWorkflowStaticData('global');

// Passa direto se não for cena com personagem (ou se for thumbnail)
if (!meta.personagem_presente || meta._isThumbnail) {
  return [{ json: meta }];
}

const comfyuiUrl = staticData.comfyuiUrl;
const outputFilename = meta.filename;
const continuityName = 'continuity_' + meta.videoId + '.png';

try {
  // 1. Baixar PNG do /output/ como binário
  const imageBuffer = await this.helpers.httpRequest({
    method: 'GET',
    url: comfyuiUrl + '/view',
    qs: {
      filename: outputFilename,
      type: 'output'
    },
    encoding: 'arraybuffer',
    returnFullResponse: false
  });

  // 2. Upload multipart para /input/
  const FormData = require('form-data');
  const formData = new FormData();
  formData.append('image', Buffer.from(imageBuffer), {
    filename: continuityName,
    contentType: 'image/png'
  });
  formData.append('type', 'input');
  formData.append('subfolder', '');
  formData.append('overwrite', 'true');

  await this.helpers.httpRequest({
    method: 'POST',
    url: comfyuiUrl + '/upload/image',
    body: formData,
    headers: formData.getHeaders()
  });

  // 3. Registrar nome do arquivo em /input/ para próxima cena com continuidade
  staticData.lastPersonagemImage = continuityName;

} catch (e) {
  // Se falhar, loga mas não quebra o loop — a próxima cena cairá no
  // fallback da Imagem Mestre Personagem.
  console.log('[Regra 29] Falha ao copiar output→input: ' + (e.message || e));
  staticData.lastPersonagemImage = null;
}

return [{ json: meta }];
